"use client";

import { useEffect, useState } from "react";

type GlobusProject = {
  id: string;
  code: string;
  name: string;
  description: string;
  kind: string;
  status: string;
  priority: number;
  tags: string[];
};

export default function HomePage() {
  const [projects, setProjects] = useState<GlobusProject[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchProjects = async () => {
      try {
        const baseUrl =
          process.env.NEXT_PUBLIC_API_BASE_URL || "http://localhost:4001";

        const res = await fetch(`${baseUrl}/api/globus/projects`);
        if (!res.ok) throw new Error("Failed to load projects");

        const data = await res.json();
        setProjects(data.items || []);
      } catch (e) {
        setError((e as Error).message);
      } finally {
        setLoading(false);
      }
    };

    fetchProjects();
  }, []);

  if (loading) return <div style={{ padding: 20 }}>Загрузка проектов…</div>;
  if (error) return <div style={{ padding: 20 }}>Ошибка: {error}</div>;

  return (
    <main style={{ padding: 20 }}>
      <h1 style={{ fontSize: 26, marginBottom: 20 }}>AEVION Portal</h1>

      <div style={{ marginBottom: 15 }}>
        Всего проектов: <b>{projects.length}</b>
      </div>

      <div style={{ display: "grid", gap: 15 }}>
        {projects.map((p) => (
          <div
            key={p.id}
            style={{
              padding: 12,
              border: "1px solid #ccc",
              borderRadius: 8,
            }}
          >
            <div style={{ fontSize: 12, color: "#666" }}>
              {p.code} • {p.kind} • {p.status}
            </div>
            <h2 style={{ fontSize: 18, margin: "8px 0" }}>{p.name}</h2>
            <p style={{ fontSize: 14 }}>{p.description}</p>
          </div>
        ))}
      </div>
    </main>
  );
}
